const fs = require('fs');
const path = require('path');

const textFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go', 'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp', 'makefile', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python', 'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql', 'svg', 'symlinktext', 'vba', 'winregistry', 'yaml'];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const validFileTypes = textFileTypes.concat(binaryFileTypes);

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(filesToPush, folder) {
  try {
    const files = fs.readdirSync(folder, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const filePath = path.join(file.path || folder, file.name);
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      }
      if (file.isDirectory()) {
        processDirectory(filesToPush, filePath);
      }
    }
  } catch (err) {
    console.error(`Error reading directory: ${err.message}`);
  }
}

const files = $input.first().json.files || [];
const folders = $input.first().json.folders || [];
let filesToPush = [];

for (const file of files) {
  if (fs.existsSync(file.path)) {
    filesToPush.push(file.path);
  }
}

for (const folder of folders) {
  if (fs.existsSync(folder.path)) {
    processDirectory(filesToPush, folder.path);
  }
}

return { filesToPush, lastSync: $input.first().json.lastSync || [] };

const fs = require('fs');

const filesToPush = $input.first().json.filesToPush;
const lastSync = $input.first().json.lastSync;
const regenerate = $input.first().json.regenerate || false;

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const filesDataToPush = [];
const state = { completed: true };

for (const file of filesToPush) {
  try {
    const stats = fs.statSync(file);
    if (!regenerate) {
      const lastSyncEntry = lastSync.find(s => s.path === file);
      if (lastSyncEntry && stats.mtime.toISOString() < lastSyncEntry.datetime) {
        continue;
      }
    }

    const encoding = binaryFileTypes.includes(file.split('.').pop()) ? 'binary' : 'utf8';
    const fileContent = fs.readFileSync(file, { encoding });
    filesDataToPush.push({
      path: file,
      content: fileContent,
      encoding: encoding
    });
    state[file] = { success: true };
  } catch (err) {
    state[file] = { success: false, error: err.message };
  }
}

// Mark deleted files
for (const syncedFile of lastSync) {
  if (!filesToPush.includes(syncedFile.path)) {
    filesDataToPush.push({
      path: syncedFile.path,
      content: '',
      deleted: true
    });
  }
}

return { filesDataToPush, state };

const filesDataToPush = $input.first().json.filesDataToPush;
const response = $input.previous().json;

const lastSync = filesDataToPush
  .filter(f => !f.deleted && response.includes(f.path))
  .map(f => ({
    path: f.path,
    datetime: new Date().toISOString()
  }));

return { lastSync, success: true };

return {
  message: 'Sync completed successfully',
  timestamp: new Date().toISOString()
};

const error = $input.first().json.error || 'Unknown error';
return {
  message: 'Sync failed',
  error: error,
  timestamp: new Date().toISOString()
};
